// ============================================================
// Читаем все строки из Sheet с колонками: «Звонок», «Текст».
// Режем до maxFilesFromArchive, склеиваем в один fullText.
// ============================================================
const items = $input.all();
const meta = $('Set Metadata').first().json;

if (items.length === 0) {
  throw new Error(
    'Sheet вернул 0 строк.\n' +
    'Проверьте:\n' +
    '  • archiveSheetId в Set Metadata указан правильно\n' +
    '  • в листе «' + meta.archiveSheetName + '» есть данные\n' +
    '  • у credential Google Sheets есть доступ к этой таблице'
  );
}

function pick(row, names) {
  for (const n of names) {
    if (row[n] !== undefined && row[n] !== null && String(row[n]).length > 0) {
      return String(row[n]);
    }
  }
  return '';
}

const matched = [];
const skipped = { noTranscript: 0, noCallId: 0 };

for (const item of items) {
  const r = item.json;
  const transcript = pick(r, ['Текст', 'text', 'transcript']).trim();
  if (!transcript) { skipped.noTranscript++; continue; }
  const callIdRaw = pick(r, ['Звонок', 'call', 'call_id']).trim();
  if (!callIdRaw) { skipped.noCallId++; continue; }
  const m = callIdRaw.match(/#\s*(\S+)/);
  const callNumber = m ? m[1] : callIdRaw;
  matched.push({
    callId: callIdRaw.startsWith('Звонок') ? callIdRaw : `Звонок #${callIdRaw}`,
    callNumber,
    transcript
  });
}

if (matched.length === 0) {
  throw new Error(
    `Из ${items.length} строк ни одна не содержит валидных данных.\n` +
    `Без транскрипта: ${skipped.noTranscript}\n` +
    `Без идентификатора: ${skipped.noCallId}`
  );
}

const maxFiles = parseInt(meta.maxFilesFromArchive || '500', 10);
const limited = matched.slice(0, maxFiles);

const fullText = limited
  .map((r, i) => {
    const header = `Звонок #${i + 1} | ID: ${r.callId}`;
    return header + '\n\n' + r.transcript;
  })
  .join('\n\n---\n\n');

const combinedLabel = `Архив (${limited.length} звонков из ${matched.length} в Sheet ${items.length})`;

return [{
  json: {
    client:           meta.client,
    periodStart:      meta.periodStart,
    periodEnd:        meta.periodEnd,
    employee:         meta.employee,
    reportType:       meta.reportType,
    reason1:          meta.reason1,
    reason2:          meta.reason2,
    fileName:         combinedLabel,
    uploadTimestamp:  new Date().toISOString(),
    sourceFiles:      limited.length,
    matchedRows:      matched.length,
    totalRowsInSheet: items.length,
    skippedReasons:   skipped,
    fullText
  }
}];

const fullText = $json.fullText;
const metadata = {
  client:      $json.client,
  periodStart: $json.periodStart,
  periodEnd:   $json.periodEnd,
  employee:    $json.employee,
  reportType:  $json.reportType,
  reason1:     $json.reason1,
  reason2:     $json.reason2,
  fileName:    $json.fileName,
  sourceFiles: $json.sourceFiles
};

const callRegex = /^(Звонок #\d+)/gm;
const calls = [];
let match;

const matches = [];
while ((match = callRegex.exec(fullText)) !== null) {
  matches.push({ key: match[1], index: match.index });
}

for (let i = 0; i < matches.length; i++) {
  const start = matches[i].index;
  const end = i + 1 < matches.length ? matches[i + 1].index : fullText.length;
  const callText = fullText.substring(start, end).trim();
  if (callText) calls.push(callText);
}

const CHUNK_SIZE = 50;
const chunks = [];
for (let i = 0; i < calls.length; i += CHUNK_SIZE) {
  const chunkCalls = calls.slice(i, i + CHUNK_SIZE);
  chunks.push({
    json: {
      ...metadata,
      chunkIndex: Math.floor(i / CHUNK_SIZE),
      totalChunks: Math.ceil(calls.length / CHUNK_SIZE),
      callsInChunk: chunkCalls.length,
      totalCalls: calls.length,
      chunkText: chunkCalls.join('\n\n')
    }
  });
}

return chunks;

const items = $input.all();
const results = [];
const meta = $('Chunk Parser').item.json;

function extractText(j) {
  if (Array.isArray(j.output)) {
    const parts = [];
    for (const out of j.output) {
      if (out?.type === 'message' && Array.isArray(out.content)) {
        for (const c of out.content) {
          if ((c?.type === 'output_text' || c?.type === 'text') && c.text) parts.push(c.text);
        }
      } else if (out?.text) parts.push(out.text);
    }
    if (parts.length) return parts.join('\n\n');
  }
  if (Array.isArray(j.content)) {
    const parts = j.content.filter(c => c?.text).map(c => c.text);
    if (parts.length) return parts.join('\n\n');
  }
  if (typeof j.content === 'string' && j.content) return j.content;
  if (j.message?.content) return j.message.content;
  if (j.choices?.[0]?.message?.content) return j.choices[0].message.content;
  if (j.output_text) return Array.isArray(j.output_text) ? j.output_text.join('\n\n') : j.output_text;
  if (typeof j.text === 'string' && j.text) return j.text;
  if (typeof j === 'string') return j;
  return '';
}

for (const item of items) {
  const j = item.json;
  const responseText = extractText(j);

  if (!responseText) {
    throw new Error('Не удалось извлечь текст из ответа OpenAI: ' + JSON.stringify(j).slice(0, 800));
  }

  results.push({
    json: {
      chunkIndex:    meta.chunkIndex,
      totalChunks:   meta.totalChunks,
      callsInChunk:  meta.callsInChunk,
      totalCalls:    meta.totalCalls,
      client:        meta.client,
      periodStart:   meta.periodStart,
      periodEnd:     meta.periodEnd,
      employee:      meta.employee,
      reportType:    meta.reportType,
      reason1:       meta.reason1,
      reason2:       meta.reason2,
      fileName:      meta.fileName,
      sourceFiles:   meta.sourceFiles,
      markdownReport: responseText
    }
  });
}

return results;

const inputs = $input.all().map(i => i.json);

let allChunks = [];
for (const top of inputs) {
  if (top && Array.isArray(top.allChunks)) {
    for (const c of top.allChunks) if (c) allChunks.push(c);
  } else if (top) {
    allChunks.push(top);
  }
}
allChunks.sort((a, b) => (a.chunkIndex || 0) - (b.chunkIndex || 0));

const meta = allChunks[0] || {};
const totalCalls = meta.totalCalls
  || allChunks.reduce((sum, c) => sum + (c.callsInChunk || 0), 0)
  || allChunks.length;

const sourceFiles = meta.sourceFiles || totalCalls;

// Склеиваем markdown от всех чанков
let combinedMarkdown;
if (allChunks.length === 1) {
  combinedMarkdown = allChunks[0].markdownReport || '';
} else {
  combinedMarkdown = allChunks
    .map((c, i) => `# Часть ${i + 1} из ${allChunks.length}\n\n${c.markdownReport || ''}`)
    .join('\n\n---\n\n');
}

// Определяем тип отчёта для заголовка
const reportType = meta.reportType || 'employee';
const reportTitle = reportType === 'general'
  ? '📊 Общий аналитический отчёт по звонкам'
  : '📊 Аналитический отчёт по менеджеру';

// Причины (для общего отчёта)
const reasons = [meta.reason1, meta.reason2].filter(r => r && r.trim());
const reasonsLabel = reasons.length > 0
  ? reasons.join(', ')
  : '';

// ---------- Markdown → HTML конвертер ----------
function esc(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function mdToHtml(md) {
  if (!md) return '';
  const lines = md.split('\n');
  const out = [];
  let i = 0;

  const inlineFmt = (s) => {
    let x = esc(s);
    x = x.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
    x = x.replace(/\*([^*\n]+)\*/g, '<em>$1</em>');
    x = x.replace(/`([^`]+)`/g, '<code>$1</code>');
    return x;
  };

  while (i < lines.length) {
    const line = lines[i];
    const trimmed = line.trim();
    if (!trimmed) { i++; continue; }
    if (/^---+$/.test(trimmed)) { out.push('<hr>'); i++; continue; }
    const h = trimmed.match(/^(#{1,6})\s+(.+)$/);
    if (h) {
      const lvl = h[1].length;
      out.push(`<h${lvl}>${inlineFmt(h[2])}</h${lvl}>`);
      i++; continue;
    }
    if (trimmed.startsWith('|') && trimmed.endsWith('|')) {
      const next = (lines[i + 1] || '').trim();
      const isTable = /^\|[\s:|-]+\|$/.test(next);
      if (isTable) {
        const headerCells = trimmed.split('|').slice(1, -1).map(c => c.trim());
        let html = '<table><thead><tr>';
        headerCells.forEach(c => html += `<th>${inlineFmt(c)}</th>`);
        html += '</tr></thead><tbody>';
        i += 2;
        while (i < lines.length) {
          const row = lines[i].trim();
          if (!row.startsWith('|') || !row.endsWith('|')) break;
          const cells = row.split('|').slice(1, -1).map(c => c.trim());
          html += '<tr>';
          cells.forEach(c => html += `<td>${inlineFmt(c)}</td>`);
          html += '</tr>';
          i++;
        }
        html += '</tbody></table>';
        out.push(html);
        continue;
      }
    }
    if (/^[-•*]\s+/.test(trimmed) || /^—\s+/.test(trimmed)) {
      let html = '<ul>';
      while (i < lines.length) {
        const t = lines[i].trim();
        const m = t.match(/^(?:[-•*]|—)\s+(.+)$/);
        if (!m) break;
        html += `<li>${inlineFmt(m[1])}</li>`;
        i++;
      }
      html += '</ul>';
      out.push(html);
      continue;
    }
    if (/^\d+\.\s+/.test(trimmed)) {
      let html = '<ol>';
      while (i < lines.length) {
        const t = lines[i].trim();
        const m = t.match(/^\d+\.\s+(.+)$/);
        if (!m) break;
        html += `<li>${inlineFmt(m[1])}</li>`;
        i++;
      }
      html += '</ol>';
      out.push(html);
      continue;
    }
    const para = [trimmed];
    i++;
    while (i < lines.length && lines[i].trim() && !/^(#{1,6}\s|[-•*—]\s|\d+\.\s|\||---+$)/.test(lines[i].trim())) {
      para.push(lines[i].trim());
      i++;
    }
    out.push(`<p>${inlineFmt(para.join(' '))}</p>`);
  }
  return out.join('\n');
}

const reportBodyHtml = mdToHtml(combinedMarkdown);
const currentDate = new Date().toLocaleDateString('ru-RU');
const periodLabel = (meta.periodStart || meta.periodEnd)
  ? `${esc(meta.periodStart || '—')} — ${esc(meta.periodEnd || '—')}`
  : '—';

const htmlReport = `<!DOCTYPE html>
<html lang="ru">
<head>
  <meta charset="UTF-8">
  <title>${esc(reportTitle)} — ${esc(meta.client || '')}</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: 'Inter', -apple-system, sans-serif; font-size: 11pt; line-height: 1.6; color: #1a1a2e; background: #fff; padding: 40px; max-width: 1100px; margin: 0 auto; }
    .title-page { text-align: center; padding: 40px 0 30px; border-bottom: 3px solid #0f3460; margin-bottom: 32px; }
    .title-page h1 { font-size: 26pt; color: #0f3460; margin-bottom: 10px; font-weight: 700; }
    .title-page .subtitle { font-size: 15pt; color: #16213e; margin-bottom: 16px; font-weight: 500; }
    .title-page p { font-size: 10.5pt; color: #555; margin: 3px 0; }
    .stat-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 12px; margin: 0 0 28px; }
    .stat-card { background: #f0f4ff; border-radius: 8px; padding: 14px; text-align: center; }
    .stat-card .number { font-size: 24pt; font-weight: 700; color: #0f3460; }
    .stat-card .label { font-size: 9pt; color: #666; margin-top: 4px; }
    .report-body h1 { font-size: 18pt; color: #0f3460; border-bottom: 2px solid #0f3460; padding-bottom: 8px; margin: 32px 0 14px; }
    .report-body h2 { font-size: 15pt; color: #0f3460; border-bottom: 1px solid #d0d7e2; padding-bottom: 6px; margin: 24px 0 12px; }
    .report-body h3 { font-size: 12.5pt; color: #16213e; margin: 18px 0 8px; }
    .report-body h4 { font-size: 11.5pt; color: #16213e; margin: 14px 0 6px; }
    .report-body p { margin: 8px 0; }
    .report-body ul, .report-body ol { margin: 8px 0 12px 22px; }
    .report-body li { margin: 3px 0; }
    .report-body strong { color: #0f3460; }
    .report-body code { background: #f4f4f6; padding: 1px 5px; border-radius: 3px; font-size: 95%; }
    .report-body hr { border: none; border-top: 1px dashed #c0c8d4; margin: 28px 0; }
    .report-body table { width: 100%; border-collapse: collapse; margin: 12px 0 18px; font-size: 10pt; }
    .report-body th { background: #0f3460; color: #fff; padding: 8px 10px; text-align: left; font-weight: 600; }
    .report-body td { padding: 7px 10px; border-bottom: 1px solid #e0e0e0; vertical-align: top; }
    .report-body tr:nth-child(even) td { background: #f8f9fa; }
    @media print { body { padding: 20px; max-width: none; } .title-page { page-break-after: always; } .report-body h1, .report-body h2 { page-break-after: avoid; } .report-body table { page-break-inside: avoid; } }
  </style>
</head>
<body>
  <div class="title-page">
    <h1>${esc(reportTitle)}</h1>
    <p class="subtitle">${esc(meta.client || 'Клиент')}</p>
    <p>📅 Период: ${periodLabel}</p>
    <p>👤 ${reportType === 'general' ? 'Тип: Общий отчёт' : 'Сотрудник: ' + esc(meta.employee || 'Все сотрудники')}</p>
    ${reasonsLabel ? `<p>🔍 Причины анализа: ${esc(reasonsLabel)}</p>` : ''}
    <p>🗓️ Дата формирования: ${currentDate}</p>
  </div>

  <div class="stat-grid">
    <div class="stat-card"><div class="number">${totalCalls}</div><div class="label">Звонков в анализе</div></div>
    <div class="stat-card"><div class="number">${sourceFiles}</div><div class="label">Файлов обработано</div></div>
  </div>

  <div class="report-body">
${reportBodyHtml}
  </div>
</body>
</html>`;

return [{
  json: {
    meta: {
      client:      meta.client,
      periodStart: meta.periodStart,
      periodEnd:   meta.periodEnd,
      employee:    meta.employee,
      reportType:  meta.reportType,
      reason1:     meta.reason1,
      reason2:     meta.reason2
    },
    totalCalls,
    sourceFiles,
    htmlReport
  }
}];

const htmlReport = $json.htmlReport;
const meta = $json.meta || {};
const totalCalls = $json.totalCalls || 0;
const sourceFiles = $json.sourceFiles || 0;

const safeName = (s) => String(s || '').replace(/[^\wа-яА-ЯёЁ\-]/g, '_').slice(0, 60);
const reportTypeLabel = meta.reportType === 'general' ? 'Общий' : safeName(meta.employee || 'звонки');
const fileName = `Отчёт_${reportTypeLabel}_${safeName(meta.client || '')}_${meta.periodStart || ''}_${meta.periodEnd || ''}.html`;

const buffer = Buffer.from(htmlReport, 'utf-8');
const b64 = buffer.toString('base64');

return [{
  json: {
    fileName,
    totalCalls,
    sourceFiles,
    htmlReport,
    meta
  },
  binary: {
    report: {
      data: b64,
      mimeType: 'text/html',
      fileName: fileName
    }
  }
}];

const lookupItem = $input.item;
const pdfItem = $('Convert to PDF (PDFShift)').first();
const reportItem = $('Generate Report File').first();

if (!lookupItem || !lookupItem.json || !lookupItem.json.chat_id) {
  throw new Error('Не найден chat_id — пользователь не зарегистрирован у бота.');
}

let binaryToSend = null;
let attachmentName = '';

if (pdfItem && pdfItem.binary && pdfItem.binary.report_pdf) {
  const pdfBin = pdfItem.binary.report_pdf;
  attachmentName = (reportItem?.json?.fileName || 'report')
    .replace(/\.html?$/i, '') + '.pdf';
  binaryToSend = {
    data: pdfBin.data,
    mimeType: 'application/pdf',
    fileName: attachmentName,
    fileExtension: 'pdf'
  };
} else if (reportItem?.binary?.report) {
  attachmentName = reportItem.json?.fileName || 'report.html';
  binaryToSend = reportItem.binary.report;
} else {
  throw new Error('Нет ни PDF, ни HTML отчёта для отправки в Telegram.');
}

return {
  json: {
    chat_id:    lookupItem.json.chat_id,
    username:   lookupItem.json.username,
    first_name: lookupItem.json.first_name,
    fileName:   attachmentName,
    totalCalls: reportItem?.json?.totalCalls || 0,
    sourceFiles: reportItem?.json?.sourceFiles || 0,
    pdfStatus:  pdfItem?.binary?.report_pdf ? 'pdf' : 'html-fallback'
  },
  binary: {
    report: binaryToSend
  }
};

// Извлекаем уникальные имена из столбца operator
const items = $input.all();
const employeeSet = new Set();

for (const item of items) {
  const r = item.json;
  // Ищем значение в разных вариантах названия столбца
  const val = r['operator'] || r['Operator'] || r['Оператор'] || r['оператор'] || '';
  const name = String(val).trim();
  if (name && name !== 'operator' && name !== 'Operator') {
    employeeSet.add(name);
  }
}

const employees = Array.from(employeeSet).sort((a, b) => a.localeCompare(b, 'ru'));

return [{
  json: {
    employees,
    count: employees.length
  }
}];

parameters.content:
🆕 API для получения списка сотрудников.
POST /webhook/employees-list
Body: { sheetUrl, sheetName }
Читает столбец operator из таблицы.
Возвращает JSON: { employees: [...], count: N }
